export type RelationshipEvidence = $Result.DefaultSelection<Prisma.$RelationshipEvidencePayload>
/**
 * Model RelationshipHistory
 * Immutable append-only audit log for every state change a Relationship
 * passes through.  One row per atomic mutation.
 * 
 * Key AI-facing fields
 * --------------------
 * changedFields  — JSON array of field names that changed in this event.
 * e.g. '["confidence","packetCount","byteCount"]'
 * AI Copilot reads this to generate targeted explanations
 * without needing to diff rows itself.
 * 
 * changeReason   — stable human-readable reason string from
 * RELATIONSHIP_CHANGE_REASON_* constants.
 * e.g. "New packet observed" | "New evidence linked"
 * AI Copilot uses this as the primary explanation label.
 * GROUP BY changeReason enables trend analytics.
 */
export type RelationshipHistory = $Result.DefaultSelection<Prisma.$RelationshipHistoryPayload>

